'use client';

import React, { createContext, useContext, useEffect, useRef } from 'react';
import { HuskelClient, getHuskelClient } from '../client';
import { HuskelConfig } from '../types';

export const HuskelContext = createContext<HuskelClient | null>(null);

interface HuskelProviderProps extends HuskelConfig {
  children: React.ReactNode;
}

export function HuskelProvider({
  siteId,
  apiUrl,
  apiToken,
  shopperId,
  vertical,
  authLoading,
  onCheckout,
  onError,
  children
}: HuskelProviderProps) {
  const clientRef = useRef<HuskelClient | null>(null);

  if (!clientRef.current) {
    clientRef.current = new HuskelClient({
      siteId,
      apiUrl,
      apiToken,
      shopperId,
      vertical,
      authLoading,
      onCheckout,
      onError
    });
  } else {
    clientRef.current.reRegister();
  }

  // Update shopperId dynamically when it changes (e.g., shopper logs in/out)
  useEffect(() => {
    clientRef.current?.setShopperId(shopperId);
  }, [shopperId]);

  // Update authLoading dynamically when it changes
  useEffect(() => {
    clientRef.current?.setAuthLoading(!!authLoading);
  }, [authLoading]);

  // Update dynamic callbacks
  useEffect(() => {
    if (clientRef.current) {
      clientRef.current.onError = onError;
      clientRef.current.onCheckout = onCheckout;
    }
  }, [onError, onCheckout]);

  // Ensure active instance is registered on mount (handles development double-mounts and fast refresh)
  useEffect(() => {
    clientRef.current?.reRegister();
  }, []);

  // Clean up the online listener and timers when the provider unmounts
  // (prevents leaks during hot module reload and React StrictMode double-mount)
  useEffect(() => {
    return () => {
      clientRef.current?.destroy();
    };
  }, []);

  return (
    <HuskelContext.Provider value={clientRef.current}>
      {children}
    </HuskelContext.Provider>
  );
}

export function useHuskelContext(): HuskelClient {
  const context = useContext(HuskelContext);
  if (!context) {
    return getHuskelClient();
  }
  return context;
}

